import { render, route, except } from "rwsdk/router";
import { defineApp } from "rwsdk/worker";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { Home } from "@/app/pages/home";
import { NotFound } from "@/app/pages/notFound";
import { ServerError } from "@/app/pages/serverError";

export type AppContext = {};

export default defineApp([
  setCommonHeaders(),
  ({ ctx }) => {
    // setup ctx here
    ctx;
  },

  // JSON API routes — these return raw Response objects, not HTML
  route("/api/boom", () => {
    throw new Error("api boom sentinel error");
  }),
  except((error, requestInfo) => {
    const path = new URL(requestInfo.request.url).pathname;
    if (path.startsWith("/api/")) {
      return new Response(JSON.stringify({ error: "internal_server_error" }), {
        status: 500,
        headers: { "Content-Type": "application/json" },
      });
    }
    // Not an API path — let HTML handler deal with it below
  }),
  route("/api/*", ({ request }) => {
    const path = new URL(request.url).pathname;
    return new Response(JSON.stringify({ error: "not_found", path }), {
      status: 404,
      headers: { "Content-Type": "application/json" },
    });
  }),

  // HTML routes wrapped in Document
  render(Document, [
    route("/", Home),

    route("/boom", () => {
      throw new Error("boom sentinel error");
    }),

    except((error, requestInfo) => {
      requestInfo.response.status = 500;
      return <ServerError />;
    }),

    route("*", ({ response }) => {
      response.status = 404;
      return <NotFound />;
    }),
  ]),
]);

